1745 template <typename LHS_t, typename RHS_t, typename Class,
1746           bool Commutable = false>
1747 struct CmpClass_match {
1748   CmpPredicate *Predicate;
1749   LHS_t L;
1750   RHS_t R;
1751 
1752   // The evaluation order is always stable, regardless of Commutability.
1753   // The LHS is always matched first.
1754   CmpClass_match(CmpPredicate &Pred, const LHS_t &LHS, const RHS_t &RHS)
1755       : Predicate(&Pred), L(LHS), R(RHS) {}
1756   CmpClass_match(const LHS_t &LHS, const RHS_t &RHS)
1757       : Predicate(nullptr), L(LHS), R(RHS) {}
1758 
1759   template <typename OpTy> bool match(OpTy *V) const {
1760     if (auto *I = dyn_cast<Class>(V)) {
1761       if (L.match(I->getOperand(0)) && R.match(I->getOperand(1))) {
1762         if (Predicate)
1763           *Predicate = CmpPredicate::get(I);
1764         return true;
1765       }
1766       if (Commutable && L.match(I->getOperand(1)) &&
1767           R.match(I->getOperand(0))) {
1768         if (Predicate)
1769           *Predicate = CmpPredicate::getSwapped(I);
1770         return true;
1771       }
1772     }
1773     return false;
1774   }
1775 };
