2745 static bool isReassociableOp(Instruction *I, unsigned IntOpcode,
2746                              unsigned FPOpcode) {
2747   if (I->getOpcode() == IntOpcode)
2748     return true;
2749   if (I->getOpcode() == FPOpcode && I->hasAllowReassoc() &&
2750       I->hasNoSignedZeros())
2751     return true;
2752   return false;
2753 }
